import React, { useState, useEffect } from 'react';
import { ShoppingBag, Menu, X } from 'lucide-react';
import { NAVIGATION_LINKS } from '../constants';

interface NavbarProps {
  cartCount: number;
}

export const Navbar: React.FC<NavbarProps> = ({ cartCount }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <nav 
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
        isScrolled ? 'bg-white/90 backdrop-blur-md shadow-sm py-4' : 'bg-transparent py-6'
      }`}
    >
      <div className="container mx-auto px-6 max-w-6xl flex items-center justify-between">
        {/* Mobile Menu Button */}
        <button 
          className="md:hidden text-gray-800"
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
          {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
        </button>

        {/* Logo */}
        <div className="text-center flex-1 md:flex-none">
          <a href="#" className="font-serif text-2xl md:text-3xl tracking-widest text-gray-900 font-bold">
            ONCE UPON
          </a>
        </div>

        {/* Desktop Links */}
        <div className="hidden md:flex space-x-12 items-center">
          {NAVIGATION_LINKS.map((link) => (
            <a 
              key={link.name} 
              href={link.href}
              className="font-sans text-sm tracking-widest text-gray-600 hover:text-brand-flamingo transition-colors uppercase"
            >
              {link.name}
            </a>
          ))}
        </div>

        {/* Cart Icon */}
        <div className="relative cursor-pointer group">
          <ShoppingBag size={24} className="text-gray-800 group-hover:text-brand-flamingo transition-colors" />
          {cartCount > 0 && (
            <span className="absolute -top-2 -right-2 bg-brand-flamingo text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full">
              {cartCount}
            </span>
          )}
        </div>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="md:hidden absolute top-full left-0 w-full bg-white shadow-lg border-t border-brand-grey py-6 px-6 flex flex-col space-y-4 animate-fade-in">
          {NAVIGATION_LINKS.map((link) => (
            <a 
              key={link.name} 
              href={link.href}
              className="font-sans text-sm tracking-widest text-gray-600 hover:text-brand-flamingo transition-colors uppercase py-2 border-b border-brand-grey last:border-0"
              onClick={() => setIsMobileMenuOpen(false)}
            >
              {link.name}
            </a>
          ))}
        </div>
      )}
    </nav>
  );
};

