import React, { useState, useEffect } from 'react';
import { ShoppingBag, Menu, X } from 'lucide-react';
import { NAVIGATION_LINKS } from '../constants';

interface NavbarProps {
  cartCount: number;
}

export const Navbar: React.FC<NavbarProps> = ({ cartCount }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Lock body scroll when mobile menu is open
  useEffect(() => {
    if (isMobileMenuOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
  }, [isMobileMenuOpen]);

  return (
    <>
      <nav 
        className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
          isScrolled ? 'bg-white/95 backdrop-blur-md shadow-sm py-3 md:py-4' : 'bg-transparent py-4 md:py-6'
        }`}
      >
        <div className="container mx-auto px-6 max-w-6xl flex items-center justify-between">
          {/* Mobile Menu Button */}
          <button 
            className="md:hidden text-gray-800 p-2 -ml-2 active:scale-95 transition-transform"
            onClick={() => setIsMobileMenuOpen(true)}
            aria-label="Open Menu"
          >
            <Menu size={24} />
          </button>

          {/* Logo */}
          <div className="text-center flex-1 md:flex-none">
            <a href="#" className="font-serif text-2xl md:text-3xl tracking-widest text-gray-900 font-bold">
              ONCE UPON
            </a>
          </div>

          {/* Desktop Links */}
          <div className="hidden md:flex space-x-12 items-center">
            {NAVIGATION_LINKS.map((link) => (
              <a 
                key={link.name} 
                href={link.href}
                className="font-sans text-sm tracking-widest text-gray-600 hover:text-brand-flamingo transition-colors uppercase"
              >
                {link.name}
              </a>
            ))}
          </div>

          {/* Cart Icon */}
          <div className="relative cursor-pointer group p-2 -mr-2">
            <ShoppingBag size={24} className="text-gray-800 group-hover:text-brand-flamingo transition-colors" />
            {cartCount > 0 && (
              <span className="absolute top-0 right-0 bg-brand-flamingo text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full animate-bounce">
                {cartCount}
              </span>
            )}
          </div>
        </div>
      </nav>

      {/* Mobile Menu Overlay - App-like Full Screen */}
      <div 
        className={`fixed inset-0 bg-white z-[60] flex flex-col transition-all duration-500 ease-in-out md:hidden ${
          isMobileMenuOpen ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-full pointer-events-none'
        }`}
      >
        <div className="flex items-center justify-between px-6 py-4 border-b border-brand-grey">
          <span className="font-serif text-xl tracking-widest text-gray-900 font-bold">MENU</span>
          <button 
            onClick={() => setIsMobileMenuOpen(false)}
            className="p-2 -mr-2 text-gray-800 active:scale-90 transition-transform"
            aria-label="Close Menu"
          >
            <X size={28} />
          </button>
        </div>

        <div className="flex-1 flex flex-col justify-center items-center space-y-8 px-6">
          {NAVIGATION_LINKS.map((link, idx) => (
            <a 
              key={link.name} 
              href={link.href}
              className={`font-serif text-3xl text-gray-900 hover:text-brand-flamingo transition-colors duration-300 transform ${
                isMobileMenuOpen ? 'translate-y-0 opacity-100' : 'translate-y-8 opacity-0'
              }`}
              style={{ transitionDelay: `${idx * 100}ms` }}
              onClick={() => setIsMobileMenuOpen(false)}
            >
              {link.name}
            </a>
          ))}
        </div>

        <div className="p-8 text-center bg-brand-grey/20">
          <p className="font-sans text-xs tracking-widest text-gray-500 uppercase">
            Est. 2024 • Paris
          </p>
        </div>
      </div>
    </>
  );
};

