        }`}
      >
        <div className="container mx-auto px-6 max-w-7xl flex items-center justify-between">

          {/* Mobile Toggle */}
          <button 
            className="md:hidden text-gray-800 p-2 -ml-2 hover:text-brand-flamingo transition-colors"
            onClick={() => setIsMobileMenuOpen(true)}
          >
            <Menu size={24} strokeWidth={1} />
          </button>

          {/* Desktop Left Links */}
          <div className="hidden md:flex space-x-8 items-center flex-1">
             <a href="#products" className="font-sans text-[11px] tracking-[0.2em] text-gray-500 hover:text-brand-flamingo transition-colors uppercase font-bold">Shop</a>
             <a href="#story" className="font-sans text-[11px] tracking-[0.2em] text-gray-500 hover:text-brand-flamingo transition-colors uppercase font-bold">Story</a>
          </div>

          {/* Logo */}
          <div className="flex-none text-center group cursor-pointer">
            <a href="#" className="flex flex-col items-center">
              <span className="font-serif text-2xl md:text-3xl tracking-widest text-gray-900 font-bold group-hover:text-brand-flamingo transition-colors duration-500">
                ONCE UPON
              </span>
              <span className={`font-script text-xl text-brand-gold -mt-1 transition-all duration-500 ${isScrolled ? 'opacity-0 h-0 overflow-hidden' : 'opacity-100 h-auto'}`}>
                Paris
              </span>
            </a>
          </div>

          {/* Desktop Right Links / Cart */}
          <div className="hidden md:flex space-x-8 items-center flex-1 justify-end">
             <a href="#atelier" className="font-sans text-[11px] tracking-[0.2em] text-gray-500 hover:text-brand-flamingo transition-colors uppercase font-bold">Atelier</a>
