import React, { useState, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { ProductCard } from './components/ProductCard';
import { Newsletter } from './components/Newsletter';
import { Footer } from './components/Footer';
import { AdminLogin } from './components/AdminLogin';
import { AdminDashboard } from './components/AdminDashboard';
import { ProductDetails } from './components/ProductDetails';
import { PRODUCTS as DEFAULT_PRODUCTS } from './constants';
import { Product, SiteConfig } from './types';
import { Star, Cloud } from 'lucide-react';

const SectionDivider = () => (
  <div className="flex items-center justify-center gap-4 py-8 opacity-40">
    <div className="h-[1px] w-12 md:w-24 bg-brand-latte"></div>
    <Star size={12} className="text-brand-latte" />
    <div className="h-[1px] w-12 md:w-24 bg-brand-latte"></div>
  </div>
);

type ViewMode = 'store' | 'login' | 'admin' | 'product_details';

const App: React.FC = () => {
  // Application State
  const [view, setView] = useState<ViewMode>('store');
  const [cartCount, setCartCount] = useState<number>(0);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);

  // Data State with Persistence
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('ou_products');
    return saved ? JSON.parse(saved) : DEFAULT_PRODUCTS;
  });

  const [siteConfig, setSiteConfig] = useState<SiteConfig>(() => {
    const saved = localStorage.getItem('ou_config');
    return saved ? JSON.parse(saved) : { heroImage: '' };
  });

  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Persist updates
  useEffect(() => {
    localStorage.setItem('ou_products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('ou_config', JSON.stringify(siteConfig));
  }, [siteConfig]);

  useEffect(() => {
    // Scroll to top when view changes
    window.scrollTo(0, 0);
  }, [view]);

  const handleAddToCart = (product: Product) => {
    setCartCount((prev) => prev + 1);
    // Optional: Show toast notification
  };

  const handleProductClick = (product: Product) => {
    setSelectedProduct(product);
    setView('product_details');
  };

  const handleBackToStore = () => {
    setSelectedProduct(null);
    setView('store');
  };

  const handleLogin = () => {
    setIsAuthenticated(true);
    setView('admin');
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setView('store');
  };

  // View Routing
  if (view === 'login') {
    return <AdminLogin onLogin={handleLogin} onCancel={() => setView('store')} />;
  }

  if (view === 'admin' && isAuthenticated) {
    return (
      <AdminDashboard 
        products={products}
        siteConfig={siteConfig}
        onUpdateProducts={setProducts}
        onUpdateSiteConfig={setSiteConfig}
        onLogout={handleLogout}
      />
    );
  }

  if (view === 'product_details' && selectedProduct) {
    return (
      <div className="min-h-screen flex flex-col bg-white">
        <Navbar cartCount={cartCount} />
        <main className="flex-grow">
          <ProductDetails 
            product={selectedProduct}
            onAddToCart={handleAddToCart}
            onBack={handleBackToStore}
          />
        </main>
        <Footer onAdminClick={() => setView('login')} />
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-white overflow-x-hidden selection:bg-brand-pink/20 selection:text-brand-flamingo">
      <Navbar cartCount={cartCount} />

      <main className="flex-grow">
        <Hero backgroundImage={siteConfig.heroImage} />

        <SectionDivider />

        <section id="products" className="py-20 md:py-24 relative">
          {/* Whimsical Background Illustrations */}
          <Cloud className="absolute top-20 left-[-20px] text-brand-grey/60 w-32 h-32 animate-float opacity-50" strokeWidth={0.5} />
          <Cloud className="absolute bottom-40 right-[-20px] text-brand-grey/60 w-24 h-24 animate-float-delayed opacity-50" strokeWidth={0.5} />

          <div className="container mx-auto px-6 max-w-6xl">
            <div className="text-center mb-20 md:mb-28 relative">
              <span className="font-script text-3xl md:text-4xl text-brand-gold mb-2 block animate-fade-in">
                The Signature Collection
              </span>
              <h2 className="font-serif text-4xl md:text-5xl text-gray-900 mb-6 leading-tight">
                Hand-Stitched <br/> <span className="italic font-light">Heirlooms</span>
              </h2>
              <div className="w-16 h-[1px] bg-brand-flamingo mx-auto my-6"></div>
            </div>

            {products.length === 0 ? (
               <div className="text-center text-gray-400 font-sans text-sm italic py-20">
                 New collections arriving soon...
               </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-x-16 gap-y-24 items-start px-4 md:px-0">
                {products.map((product, index) => (
                  <ProductCard 
                    key={product.id} 
                    product={product} 
                    onAddToCart={handleAddToCart}
                    onClick={handleProductClick}
                    index={index}
                  />
                ))}
              </div>
            )}
          </div>
        </section>

        <div className="py-10">
           <SectionDivider />
        </div>

        {/* Testimonial Section */}
        <section className="py-24 md:py-32 relative overflow-hidden bg-brand-grey/10">
           <div className="absolute top-0 left-0 right-0 h-2 scallop-border opacity-20"></div>

          <div className="container mx-auto px-6 max-w-3xl text-center relative z-10">
            <div className="mb-8 flex justify-center">
               <div className="flex gap-1">
                 {[1,2,3,4,5].map(i => <Star key={i} size={12} className="text-brand-gold fill-brand-gold" />)}
               </div>
            </div>

            <blockquote className="font-serif text-2xl md:text-4xl text-gray-900 italic leading-snug mb-10 px-4 relative">
              <span className="absolute -top-8 left-0 md:-left-8 font-script text-8xl text-brand-cream opacity-50 select-none">"</span>
              The only blanket my daughter sleeps with. It feels like a cloud and washes beautifully. Pure magic.
            </blockquote>

            <cite className="not-italic flex flex-col items-center gap-1">
              <span className="font-sans text-xs font-bold tracking-[0.2em] uppercase text-gray-900">Sophie M.</span>
              <span className="font-script text-xl text-brand-flamingo">Kuala Lumpur</span>
            </cite>
          </div>

           <div className="absolute bottom-0 left-0 right-0 h-2 scallop-border opacity-20 rotate-180"></div>
        </section>

        <Newsletter />
      </main>

      <Footer onAdminClick={() => setView('login')} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Product, SiteConfig } from '../types';
import { Trash2, Edit2, Plus, Image as ImageIcon, LogOut, Save } from 'lucide-react';

interface AdminDashboardProps {
  products: Product[];
  siteConfig: SiteConfig;
  onUpdateProducts: (products: Product[]) => void;
  onUpdateSiteConfig: (config: SiteConfig) => void;
  onLogout: () => void;
}

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, 
  siteConfig, 
  onUpdateProducts, 
  onUpdateSiteConfig,
  onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'settings'>('products');
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [isEditing, setIsEditing] = useState(false);

  // Form State
  const [formData, setFormData] = useState<Product>({
    id: '',
    name: '',
    price: 0,
    description: '',
    image: '',
    badge: '',
    material: '',
    care: ''
  });

  const handleEdit = (product: Product) => {
    setFormData(product);
    setEditingProduct(product);
    setIsEditing(true);
  };

  const handleCreate = () => {
    setFormData({
      id: Date.now().toString(),
      name: '',
      price: 0,
      description: '',
      image: 'https://images.unsplash.com/photo-1513159446162-54eb8bdaa79b?auto=format&fit=crop&q=80',
      badge: '',
      material: '',
      care: ''
    });
    setEditingProduct(null);
    setIsEditing(true);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Are you sure you want to remove this product?')) {
      onUpdateProducts(products.filter(p => p.id !== id));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProduct) {
      onUpdateProducts(products.map(p => p.id === editingProduct.id ? formData : p));
    } else {
      onUpdateProducts([...products, formData]);
    }
    setIsEditing(false);
  };

  return (
    <div className="min-h-screen bg-brand-grey/10 font-sans">
      {/* Admin Nav */}
      <nav className="bg-white border-b border-brand-latte/20 px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-4">
          <span className="font-serif text-xl font-bold tracking-wider">ONCE UPON</span>
          <span className="bg-brand-grey px-2 py-0.5 text-[10px] uppercase tracking-wider font-bold text-gray-500 rounded">Admin</span>
        </div>
        <div className="flex items-center gap-6">
          <button 
            onClick={() => setActiveTab('products')}
            className={`text-xs uppercase tracking-widest font-bold transition-colors ${activeTab === 'products' ? 'text-brand-flamingo' : 'text-gray-400'}`}
          >
            Products
          </button>
          <button 
            onClick={() => setActiveTab('settings')}
            className={`text-xs uppercase tracking-widest font-bold transition-colors ${activeTab === 'settings' ? 'text-brand-flamingo' : 'text-gray-400'}`}
          >
            Settings
          </button>
          <button onClick={onLogout} className="text-gray-400 hover:text-gray-900">
            <LogOut size={18} />
          </button>
        </div>
      </nav>

      <div className="container mx-auto px-6 py-12 max-w-6xl">

        {activeTab === 'products' ? (
          <>
            <div className="flex justify-between items-center mb-8">
              <h2 className="font-serif text-3xl text-gray-900">Product Management</h2>
              <button 
                onClick={handleCreate}
                className="flex items-center gap-2 bg-gray-900 text-white px-6 py-3 text-[10px] font-bold uppercase tracking-widest hover:bg-brand-flamingo transition-colors"
              >
                <Plus size={14} /> Add Product
              </button>
            </div>

            {isEditing ? (
              <div className="bg-white p-8 border border-brand-latte/20 shadow-sm animate-fade-in max-w-2xl mx-auto">
                 <h3 className="font-serif text-2xl mb-6">{editingProduct ? 'Edit Product' : 'New Product'}</h3>
                 <form onSubmit={handleSubmit} className="flex flex-col gap-6">
                    <div>
                      <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Product Name</label>
                      <input required className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Price ($)</label>
                        <input required type="number" className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none" value={formData.price} onChange={e => setFormData({...formData, price: Number(e.target.value)})} />
                      </div>
                      <div>
                        <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Badge (Optional)</label>
                        <input className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none" placeholder="e.g. New" value={formData.badge} onChange={e => setFormData({...formData, badge: e.target.value})} />
                      </div>
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Description</label>
                      <textarea required rows={3} className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
                    </div>
                    <div>
                       <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Material</label>
                       <input className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none" value={formData.material || ''} onChange={e => setFormData({...formData, material: e.target.value})} />
                    </div>
                    <div>
                       <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Care Instructions</label>
                       <textarea rows={2} className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none" value={formData.care || ''} onChange={e => setFormData({...formData, care: e.target.value})} />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Image URL</label>
                      <input required className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none" value={formData.image} onChange={e => setFormData({...formData, image: e.target.value})} />
                      {formData.image && <img src={formData.image} alt="Preview" className="w-20 h-20 object-cover mt-2 border border-brand-latte/30" />}
                    </div>
                    <div className="flex justify-end gap-3 mt-4">
                      <button type="button" onClick={() => setIsEditing(false)} className="px-6 py-3 text-[10px] font-bold uppercase tracking-widest text-gray-500 hover:text-gray-900">Cancel</button>
                      <button type="submit" className="bg-brand-flamingo text-white px-8 py-3 text-[10px] font-bold uppercase tracking-widest hover:bg-brand-flamingo/80">Save Product</button>
                    </div>
                 </form>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {products.map(product => (
                  <div key={product.id} className="bg-white border border-brand-latte/20 p-4 flex gap-4 items-center group">
