             <button 
                className={`relative cursor-pointer group/cart transition-transform duration-300 ${animateCart ? 'scale-125' : 'scale-100'}`}
                onClick={onCartClick}
             >
                <ShoppingBag size={18} strokeWidth={1.5} className="text-gray-800 group-hover/cart:text-brand-flamingo transition-colors" />
                {cartCount > 0 && (
                  <span className="absolute -top-1 -right-1 bg-brand-flamingo text-white text-[9px] font-bold w-4 h-4 flex items-center justify-center rounded-full">
                    {cartCount}
                  </span>
                )}
             </button>
          </div>

          {/* Mobile Cart */}
          <button 
            className={`md:hidden relative cursor-pointer p-2 -mr-2 transition-transform duration-300 ${animateCart ? 'scale-125' : 'scale-100'}`}
            onClick={onCartClick}
          >
            <ShoppingBag size={22} strokeWidth={1.5} className="text-gray-800" />
            {cartCount > 0 && (
              <span className="absolute top-1 right-1 bg-brand-flamingo text-white text-[10px] font-bold w-4 h-4 flex items-center justify-center rounded-full">
                {cartCount}
              </span>
            )}
          </button>
        </div>
      </nav>

      {/* Mobile Menu */}
      <div 
        className={`fixed inset-0 bg-[#FFFDF9] z-[60] flex flex-col transition-all duration-700 cubic-bezier(0.7, 0, 0.3, 1) md:hidden ${
          isMobileMenuOpen ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-full pointer-events-none'
        }`}
      >
        {/* Background Texture for Mobile Menu */}
        <div className="absolute inset-0 bg-paper opacity-50 pointer-events-none"></div>
        <div className="absolute inset-0 border-[12px] border-double border-brand-grey pointer-events-none"></div>

        <div className="relative flex items-center justify-between px-6 py-6">
          <span className="font-serif text-xl tracking-widest text-gray-900 font-bold">MENU</span>
          <button 
            onClick={() => setIsMobileMenuOpen(false)}
