import React, { useState } from 'react';
import { Product, SiteConfig, Order } from '../types';
import { Trash2, Edit2, Plus, Image as ImageIcon, LogOut, Save, Search, User, Package, Calendar } from 'lucide-react';

interface AdminDashboardProps {
  products: Product[];
  orders: Order[];
  siteConfig: SiteConfig;
  onUpdateProducts: (products: Product[]) => void;
  onUpdateSiteConfig: (config: SiteConfig) => void;
  onUpdateOrders: (orders: Order[]) => void;
  onLogout: () => void;
}

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, 
  orders,
  siteConfig, 
  onUpdateProducts, 
  onUpdateSiteConfig,
  onUpdateOrders,
  onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'sales' | 'settings'>('products');
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // Form State
  const [formData, setFormData] = useState<Product>({
    id: '',
    name: '',
    price: 0,
    description: '',
    image: '',
    badge: '',
    material: '',
    care: ''
  });

  const handleEdit = (product: Product) => {
    setFormData(product);
    setEditingProduct(product);
    setIsEditing(true);
  };

  const handleCreate = () => {
    setFormData({
      id: Date.now().toString(),
      name: '',
      price: 0,
      description: '',
      image: 'https://images.unsplash.com/photo-1513159446162-54eb8bdaa79b?auto=format&fit=crop&q=80',
      badge: '',
      material: '',
      care: ''
    });
    setEditingProduct(null);
    setIsEditing(true);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Are you sure you want to remove this product?')) {
      onUpdateProducts(products.filter(p => p.id !== id));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProduct) {
      onUpdateProducts(products.map(p => p.id === editingProduct.id ? formData : p));
    } else {
      onUpdateProducts([...products, formData]);
    }
    setIsEditing(false);
  };

  const handleStatusToggle = (orderId: string) => {
    onUpdateOrders(orders.map(o => {
      if (o.id === orderId) {
        return { 
          ...o, 
          status: o.status === 'pending' ? 'shipped' : o.status === 'shipped' ? 'delivered' : 'pending' 
        };
      }
      return o;
    }));
  };

  // Filter Orders
  const filteredOrders = orders.filter(order => 
    order.customerName.toLowerCase().includes(searchQuery.toLowerCase()) || 
    order.customerEmail.toLowerCase().includes(searchQuery.toLowerCase()) ||
    order.id.includes(searchQuery)
  );

  return (
    <div className="min-h-screen bg-brand-grey/10 font-sans">
      {/* Admin Nav */}
      <nav className="bg-white border-b border-brand-latte/20 px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-4">
          <span className="font-serif text-xl font-bold tracking-wider">ONCE UPON</span>
          <span className="bg-brand-grey px-2 py-0.5 text-[10px] uppercase tracking-wider font-bold text-gray-500 rounded">Admin</span>
        </div>
        <div className="flex items-center gap-6">
          <button 
            onClick={() => setActiveTab('products')}
            className={`text-xs uppercase tracking-widest font-bold transition-colors ${activeTab === 'products' ? 'text-brand-flamingo' : 'text-gray-400'}`}
          >
            Products
          </button>
          <button 
            onClick={() => setActiveTab('sales')}
            className={`text-xs uppercase tracking-widest font-bold transition-colors ${activeTab === 'sales' ? 'text-brand-flamingo' : 'text-gray-400'}`}
          >
            Sales & Customers
          </button>
          <button 
            onClick={() => setActiveTab('settings')}
            className={`text-xs uppercase tracking-widest font-bold transition-colors ${activeTab === 'settings' ? 'text-brand-flamingo' : 'text-gray-400'}`}
          >
            Settings
          </button>
          <button onClick={onLogout} className="text-gray-400 hover:text-gray-900 ml-4">
            <LogOut size={18} />
          </button>
        </div>
      </nav>

      <div className="container mx-auto px-6 py-12 max-w-6xl">

        {/* PRODUCTS TAB */}
        {activeTab === 'products' && (
          <>
            <div className="flex justify-between items-center mb-8">
              <h2 className="font-serif text-3xl text-gray-900">Product Management</h2>
              <button 
                onClick={handleCreate}
                className="flex items-center gap-2 bg-gray-900 text-white px-6 py-3 text-[10px] font-bold uppercase tracking-widest hover:bg-brand-flamingo transition-colors"
              >
                <Plus size={14} /> Add Product
              </button>
            </div>

            {isEditing ? (
              <div className="bg-white p-8 border border-brand-latte/20 shadow-sm animate-fade-in max-w-2xl mx-auto">
                 <h3 className="font-serif text-2xl mb-6">{editingProduct ? 'Edit Product' : 'New Product'}</h3>
                 <form onSubmit={handleSubmit} className="flex flex-col gap-6">
                    <div>
                      <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Product Name</label>
                      <input required className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Price (RM)</label>
                        <input required type="number" className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none" value={formData.price} onChange={e => setFormData({...formData, price: Number(e.target.value)})} />
                      </div>
                      <div>
                        <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Badge (Optional)</label>
                        <input className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none" placeholder="e.g. New" value={formData.badge} onChange={e => setFormData({...formData, badge: e.target.value})} />
                      </div>
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Description</label>
                      <textarea required rows={3} className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
                    </div>
                    <div>
                       <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Material</label>
                       <input className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none" value={formData.material || ''} onChange={e => setFormData({...formData, material: e.target.value})} />
                    </div>
                    <div>
                       <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Care Instructions</label>
                       <textarea rows={2} className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none" value={formData.care || ''} onChange={e => setFormData({...formData, care: e.target.value})} />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Image URL</label>
                      <input required className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none" value={formData.image} onChange={e => setFormData({...formData, image: e.target.value})} />
                      {formData.image && <img src={formData.image} alt="Preview" className="w-20 h-20 object-cover mt-2 border border-brand-latte/30" />}
                    </div>
                    <div className="flex justify-end gap-3 mt-4">
                      <button type="button" onClick={() => setIsEditing(false)} className="px-6 py-3 text-[10px] font-bold uppercase tracking-widest text-gray-500 hover:text-gray-900">Cancel</button>
                      <button type="submit" className="bg-brand-flamingo text-white px-8 py-3 text-[10px] font-bold uppercase tracking-widest hover:bg-brand-flamingo/80">Save Product</button>
                    </div>
                 </form>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {products.map(product => (
                  <div key={product.id} className="bg-white border border-brand-latte/20 p-4 flex gap-4 items-center group">
                    <img src={product.image} alt={product.name} className="w-20 h-20 object-cover bg-gray-100" />
                    <div className="flex-1">
                      <h4 className="font-serif text-lg text-gray-900 leading-none mb-1">{product.name}</h4>
                      <p className="text-brand-gold font-script text-lg">RM {product.price}</p>
                    </div>
                    <div className="flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => handleEdit(product)} className="text-gray-400 hover:text-brand-flamingo"><Edit2 size={16} /></button>
                      <button onClick={() => handleDelete(product.id)} className="text-gray-400 hover:text-red-400"><Trash2 size={16} /></button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </>
        )}

        {/* SALES TAB */}
        {activeTab === 'sales' && (
           <div className="animate-fade-in">
             <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
               <div>
                 <h2 className="font-serif text-3xl text-gray-900">Sales & Customers</h2>
                 <p className="text-xs text-gray-400 mt-1 uppercase tracking-widest">Find customer info and manage orders</p>
               </div>

               <div className="relative w-full md:w-64">
                 <input 
                   type="text" 
                   placeholder="Search orders or customers..."
                   value={searchQuery}
                   onChange={(e) => setSearchQuery(e.target.value)}
                   className="w-full pl-10 pr-4 py-2 bg-white border border-brand-latte/30 focus:border-brand-flamingo outline-none text-sm rounded-full"
                 />
                 <Search size={14} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" />
               </div>
             </div>

             {filteredOrders.length === 0 ? (
               <div className="text-center py-24 bg-white border border-dashed border-brand-latte/30">
                 <Package size={32} className="mx-auto text-brand-latte mb-3 opacity-50" />
                 <p className="text-gray-400 text-sm">No orders found.</p>
               </div>
             ) : (
               <div className="bg-white border border-brand-latte/20 overflow-hidden shadow-sm">
                 <table className="w-full text-left border-collapse">
                   <thead>
                     <tr className="bg-brand-grey/10 border-b border-brand-latte/20">
                       <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Order ID / Date</th>
                       <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Customer</th>
                       <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Items</th>
                       <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Total</th>
                       <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Status</th>
                     </tr>
                   </thead>
                   <tbody>
                     {filteredOrders.map(order => (
                       <tr key={order.id} className="border-b border-brand-latte/10 hover:bg-brand-grey/5 transition-colors">
                         <td className="p-4">
                           <div className="font-mono text-xs text-gray-400">#{order.id.slice(-6)}</div>
                           <div className="flex items-center gap-1 text-xs text-gray-500 mt-1">
                             <Calendar size={10} /> {new Date(order.date).toLocaleDateString()}
                           </div>
                         </td>
                         <td className="p-4">
                           <div className="flex items-start gap-2">
                             <div className="bg-brand-latte/20 p-1.5 rounded-full mt-0.5">
                               <User size={12} className="text-brand-latte" />
                             </div>
                             <div>
                               <div className="font-serif text-gray-900">{order.customerName}</div>
                               <div className="text-xs text-gray-400">{order.customerEmail}</div>
                               <div className="text-[10px] text-gray-400 mt-1 max-w-[150px] leading-tight">{order.shippingAddress}</div>
                             </div>
                           </div>
                         </td>
                         <td className="p-4">
                           <div className="text-xs text-gray-600">
                             {order.items.map(i => (
                               <div key={i.id} className="mb-1">
                                 {i.quantity}x {i.name}
                               </div>
                             ))}
                           </div>
                         </td>
                         <td className="p-4 font-bold text-sm text-gray-900">
                           RM {order.total}
                         </td>
                         <td className="p-4">
                           <button 
                             onClick={() => handleStatusToggle(order.id)}
                             className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest border transition-colors ${
                               order.status === 'delivered' ? 'bg-green-50 border-green-200 text-green-700' :
                               order.status === 'shipped' ? 'bg-blue-50 border-blue-200 text-blue-700' :
                               'bg-yellow-50 border-yellow-200 text-yellow-700'
                             }`}
                           >
                             {order.status}
                           </button>
                         </td>
                       </tr>
                     ))}
                   </tbody>
                 </table>
               </div>
             )}
           </div>
        )}

        {/* SETTINGS TAB */}
        {activeTab === 'settings' && (
          <div className="max-w-xl mx-auto animate-fade-in">
            <h2 className="font-serif text-3xl text-gray-900 mb-8">Site Settings</h2>

            <div className="bg-white p-8 border border-brand-latte/20">
              <h3 className="font-bold text-xs uppercase tracking-widest text-gray-500 mb-6 flex items-center gap-2">
                <ImageIcon size={16} /> Hero Section Background
              </h3>

              <div className="mb-6">
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Background Image URL</label>
                <input 
                  className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none font-sans" 
                  placeholder="https://..."
                  value={siteConfig.heroImage} 
                  onChange={(e) => onUpdateSiteConfig({...siteConfig, heroImage: e.target.value})} 
                />
                <p className="text-[10px] text-gray-400 mt-2">Leave empty to use the default luxury nursery look.</p>
              </div>

              {siteConfig.heroImage ? (
                <div className="relative h-48 w-full overflow-hidden mb-6 border border-brand-latte/20">
                  <img src={siteConfig.heroImage} className="w-full h-full object-cover opacity-80" />
                  <div className="absolute inset-0 flex items-center justify-center bg-black/20 text-white font-bold text-xs uppercase tracking-widest">Preview</div>
                </div>
              ) : (
                <div className="p-4 bg-brand-grey/10 text-center text-xs text-gray-400 italic">
                  Using default site theme
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

