      image: 'https://images.unsplash.com/photo-1513159446162-54eb8bdaa79b?auto=format&fit=crop&q=80',
      badge: '',
      material: '',
      care: ''
    });
    setEditingProduct(null);
    setIsEditing(true);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Are you sure you want to remove this product?')) {
      onUpdateProducts(products.filter(p => p.id !== id));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProduct) {
      onUpdateProducts(products.map(p => p.id === editingProduct.id ? formData : p));
    } else {
      onUpdateProducts([...products, formData]);
    }
    setIsEditing(false);
  };

  const handleStatusToggle = (orderId: string) => {
    onUpdateOrders(orders.map(o => {
      if (o.id === orderId) {
        return { 
          ...o, 
          status: o.status === 'pending' ? 'shipped' : o.status === 'shipped' ? 'delivered' : 'pending' 
        };
      }
      return o;
    }));
  };

  // Image Upload Handler
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'product' | 'hero') => {
    const file = e.target.files?.[0];
    if (file) {
      // Basic check for file size (warn if > 2MB)
      if (file.size > 2 * 1024 * 1024) {
        alert("Warning: Large images may slow down the site. We recommend images under 2MB.");
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        if (type === 'product') {
          setFormData(prev => ({ ...prev, image: result }));
        } else {
          onUpdateSiteConfig({ ...siteConfig, heroImage: result });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  // Filter Orders
  const filteredOrders = orders.filter(order => 
    order.customerName.toLowerCase().includes(searchQuery.toLowerCase()) || 
    order.customerEmail.toLowerCase().includes(searchQuery.toLowerCase()) ||
