import React, { useState, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { ProductCard } from './components/ProductCard';
import { Newsletter } from './components/Newsletter';
import { Footer } from './components/Footer';
import { AdminLogin } from './components/AdminLogin';
import { AdminDashboard } from './components/AdminDashboard';
import { ProductDetails } from './components/ProductDetails';
import { CartView } from './components/CartView';
import { CheckoutView } from './components/CheckoutView';
import { PRODUCTS as DEFAULT_PRODUCTS } from './constants';
import { Product, SiteConfig, CartItem, Order } from './types';
import { Star, Cloud } from 'lucide-react';

const SectionDivider = () => (
  <div className="flex items-center justify-center gap-4 py-8 opacity-40">
    <div className="h-[1px] w-12 md:w-24 bg-brand-latte"></div>
    <Star size={12} className="text-brand-latte" />
    <div className="h-[1px] w-12 md:w-24 bg-brand-latte"></div>
  </div>
);

type ViewMode = 'store' | 'login' | 'admin' | 'product_details' | 'cart' | 'checkout';

const App: React.FC = () => {
  // Application State
  const [view, setView] = useState<ViewMode>('store');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);

  // Data State with Persistence
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('ou_products_v2');
    return saved ? JSON.parse(saved) : DEFAULT_PRODUCTS;
  });

  const [siteConfig, setSiteConfig] = useState<SiteConfig>(() => {
    const saved = localStorage.getItem('ou_config');
    return saved ? JSON.parse(saved) : { heroImage: '' };
  });

  // Cart State (Array of Items)
  const [cart, setCart] = useState<CartItem[]>(() => {
    const saved = localStorage.getItem('ou_cart');
    return saved ? JSON.parse(saved) : [];
  });

  // Orders State
  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('ou_orders');
    return saved ? JSON.parse(saved) : [];
  });

  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Persist updates with Error Handling (QuotaExceededError)
  useEffect(() => {
    try {
      localStorage.setItem('ou_products_v2', JSON.stringify(products));
    } catch (e) {
      console.error("Local Storage Full", e);
      alert("Storage Limit Reached! Your latest changes are saved in memory but may not persist if you reload. Try deleting old items or using smaller images.");
    }
  }, [products]);

  useEffect(() => {
    try {
      localStorage.setItem('ou_config', JSON.stringify(siteConfig));
    } catch (e) {
       console.error("Local Storage Full", e);
    }
  }, [siteConfig]);

  useEffect(() => {
    localStorage.setItem('ou_cart', JSON.stringify(cart));
  }, [cart]);

  useEffect(() => {
    localStorage.setItem('ou_orders', JSON.stringify(orders));
  }, [orders]);

  useEffect(() => {
    // Scroll to top when view changes
    window.scrollTo(0, 0);
  }, [view]);

  // Cart Handlers
  const handleAddToCart = (product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      return [...prev, { ...product, quantity: quantity }];
    });
  };

  const handleUpdateCartQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        return { ...item, quantity: Math.max(1, item.quantity + delta) };
      }
      return item;
    }));
  };

  const handleRemoveFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  // Order Handler
  const handleCreateOrder = (orderDetails: { customerName: string; customerEmail: string; shippingAddress: string }) => {
    const newOrder: Order = {
      id: Date.now().toString(),
      ...orderDetails,
      items: [...cart],
      total: cart.reduce((sum, item) => sum + (item.price * item.quantity), 0),
      status: 'pending',
      date: new Date().toISOString()
    };

    setOrders(prev => [newOrder, ...prev]);
    setCart([]);
    setView('store');
    // In a real app, you would show a success page here
    alert("Thank you! Your order has been placed.");
  };

  // Navigation Handlers
  const handleProductClick = (product: Product) => {
    setSelectedProduct(product);
    setView('product_details');
  };

  const handleBackToStore = () => {
    setSelectedProduct(null);
    setView('store');
  };

  const handleLogin = () => {
    setIsAuthenticated(true);
    setView('admin');
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setView('store');
  };

  // Cart Logic
  const cartCount = cart.reduce((sum, item) => sum + item.quantity, 0);

  // View Routing Logic
  if (view === 'login') {
    return <AdminLogin onLogin={handleLogin} onCancel={() => setView('store')} />;
  }

  if (view === 'admin' && isAuthenticated) {
    return (
      <AdminDashboard 
        products={products}
        siteConfig={siteConfig}
        orders={orders}
        onUpdateProducts={setProducts}
        onUpdateSiteConfig={setSiteConfig}
        onUpdateOrders={setOrders}
        onLogout={handleLogout}
      />
    );
  }

  // Common Layout Wrapper
  const Layout: React.FC<{ children: React.ReactNode }> = ({ children }) => (
    <div className="min-h-screen flex flex-col bg-white overflow-x-hidden selection:bg-brand-pink/20 selection:text-brand-flamingo">
      <Navbar 
        cartCount={cartCount} 
        onCartClick={() => setView('cart')} 
        onNavigate={setView}
      />
      <main className="flex-grow">
        {children}
      </main>
      <Footer onAdminClick={() => setView('login')} />
    </div>
  );

  if (view === 'checkout') {
    return (
      <CheckoutView 
        cart={cart}
        onBackToCart={() => setView('cart')}
        onCompleteOrder={handleCreateOrder}
      />
    );
  }

  if (view === 'cart') {
    return (
      <Layout>
        <CartView 
          cart={cart}
          onUpdateQuantity={handleUpdateCartQuantity}
          onRemoveItem={handleRemoveFromCart}
          onCheckout={() => setView('checkout')}
          onContinueShopping={() => setView('store')}
        />
      </Layout>
    );
  }

  if (view === 'product_details' && selectedProduct) {
    return (
      <Layout>
        <ProductDetails 
          product={selectedProduct}
          onAddToCart={handleAddToCart}
          onBack={handleBackToStore}
        />
      </Layout>
    );
  }

  // Default Store View
  return (
    <Layout>
        <Hero backgroundImage={siteConfig.heroImage} onEnterShop={() => {
           // Scroll to products
           document.getElementById('products')?.scrollIntoView({ behavior: 'smooth' });
        }}/>

        <SectionDivider />

        <section id="products" className="py-20 md:py-24 relative min-h-screen">
          {/* Whimsical Background Illustrations */}
          <Cloud className="absolute top-20 left-[-20px] text-brand-grey/60 w-32 h-32 animate-float opacity-50" strokeWidth={0.5} />
          <Cloud className="absolute bottom-40 right-[-20px] text-brand-grey/60 w-24 h-24 animate-float-delayed opacity-50" strokeWidth={0.5} />

          <div className="container mx-auto px-6 max-w-6xl">
            <div className="text-center mb-20 md:mb-28 relative">
              <span className="font-script text-3xl md:text-4xl text-brand-gold mb-2 block animate-fade-in">
                The Signature Collection
              </span>
              <h2 className="font-serif text-4xl md:text-5xl text-gray-900 mb-6 leading-tight">
                Hand-Stitched <br/> <span className="italic font-light">Heirlooms</span>
              </h2>
              <div className="w-16 h-[1px] bg-brand-flamingo mx-auto my-6"></div>
            </div>

            {products.length === 0 ? (
               <div className="text-center text-gray-400 font-sans text-sm italic py-20">
                 New collections arriving soon...
               </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-x-16 gap-y-24 items-start px-4 md:px-0">
                {products.map((product, index) => (
                  <ProductCard 
                    key={product.id} 
                    product={product} 
                    onAddToCart={(p, qty) => handleAddToCart(p, qty)}
                    onClick={handleProductClick}
                    index={index}
                  />
                ))}
              </div>
            )}
          </div>
        </section>

        <div className="py-10">
           <SectionDivider />
        </div>

        {/* Testimonial Section */}
        <section className="py-24 md:py-32 relative overflow-hidden bg-brand-grey/10">
           <div className="absolute top-0 left-0 right-0 h-2 scallop-border opacity-20"></div>

          <div className="container mx-auto px-6 max-w-3xl text-center relative z-10">
            <div className="mb-8 flex justify-center">
               <div className="flex gap-1">
                 {[1,2,3,4,5].map(i => <Star key={i} size={12} className="text-brand-gold fill-brand-gold" />)}
               </div>
            </div>

            <blockquote className="font-serif text-2xl md:text-4xl text-gray-900 italic leading-snug mb-10 px-4 relative">
              <span className="absolute -top-8 left-0 md:-left-8 font-script text-8xl text-brand-cream opacity-50 select-none">"</span>
              The only blanket my daughter sleeps with. It feels like a cloud and washes beautifully. Pure magic.
            </blockquote>

            <cite className="not-italic flex flex-col items-center gap-1">
              <span className="font-sans text-xs font-bold tracking-[0.2em] uppercase text-gray-900">Sophie M.</span>
              <span className="font-script text-xl text-brand-flamingo">Kuala Lumpur</span>
            </cite>
          </div>

           <div className="absolute bottom-0 left-0 right-0 h-2 scallop-border opacity-20 rotate-180"></div>
        </section>

        <Newsletter />
    </Layout>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Product, SiteConfig, Order } from '../types';
import { Trash2, Edit2, Plus, Image as ImageIcon, LogOut, Save, Search, User, Package, Calendar, Menu, Upload, X, Loader2, Check } from 'lucide-react';

interface AdminDashboardProps {
  products: Product[];
  orders: Order[];
  siteConfig: SiteConfig;
  onUpdateProducts: (products: Product[]) => void;
  onUpdateSiteConfig: (config: SiteConfig) => void;
  onUpdateOrders: (orders: Order[]) => void;
  onLogout: () => void;
}

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, 
  orders,
  siteConfig, 
  onUpdateProducts, 
  onUpdateSiteConfig,
  onUpdateOrders,
  onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'sales' | 'settings'>('products');
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');

  // Refs for file inputs
  const productFileInputRef = useRef<HTMLInputElement>(null);
  const heroFileInputRef = useRef<HTMLInputElement>(null);

  // Form State
  const [formData, setFormData] = useState<Product>({
    id: '',
    name: '',
    price: 0,
    description: '',
    image: '',
    badge: '',
    material: '',
    care: ''
  });

  const handleEdit = (product: Product) => {
    setFormData(product);
    setEditingProduct(product);
    setIsEditing(true);
    setSaveStatus('idle');
  };

  const handleCreate = () => {
    setFormData({
      id: Date.now().toString(),
      name: '',
      price: 0,
      description: '',
      image: 'https://images.unsplash.com/photo-1513159446162-54eb8bdaa79b?auto=format&fit=crop&q=80',
      badge: '',
      material: '',
      care: ''
    });
    setEditingProduct(null);
    setIsEditing(true);
    setSaveStatus('idle');
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Are you sure you want to remove this product?')) {
      onUpdateProducts(products.filter(p => p.id !== id));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSaveStatus('saving');

    // Simulate a brief delay for better UX
    setTimeout(() => {
      if (editingProduct) {
        onUpdateProducts(products.map(p => p.id === editingProduct.id ? formData : p));
      } else {
        onUpdateProducts([...products, formData]);
      }
      setSaveStatus('saved');

      // Close form after success
      setTimeout(() => {
        setIsEditing(false);
        setSaveStatus('idle');
      }, 500);
    }, 600);
  };

  const handleStatusToggle = (orderId: string) => {
    onUpdateOrders(orders.map(o => {
      if (o.id === orderId) {
        return { 
          ...o, 
          status: o.status === 'pending' ? 'shipped' : o.status === 'shipped' ? 'delivered' : 'pending' 
        };
      }
      return o;
    }));
  };

  // Image Upload Handler
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'product' | 'hero') => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        alert("Warning: Large images may slow down the site. We recommend images under 2MB.");
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        if (type === 'product') {
          setFormData(prev => ({ ...prev, image: result }));
        } else {
          onUpdateSiteConfig({ ...siteConfig, heroImage: result });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  // Filter Orders
  const filteredOrders = orders.filter(order => 
    order.customerName.toLowerCase().includes(searchQuery.toLowerCase()) || 
    order.customerEmail.toLowerCase().includes(searchQuery.toLowerCase()) ||
    order.id.includes(searchQuery)
  );

  return (
    <div className="min-h-screen bg-brand-grey/10 font-sans pb-20">
      {/* Admin Nav - Scrollable on mobile */}
      <nav className="bg-white border-b border-brand-latte/20 sticky top-0 z-40">
        <div className="px-4 md:px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <span className="font-serif text-lg md:text-xl font-bold tracking-wider">ONCE UPON</span>
              <span className="bg-brand-grey px-2 py-0.5 text-[10px] uppercase tracking-wider font-bold text-gray-500 rounded">Admin</span>
            </div>
            <button onClick={onLogout} className="md:hidden text-gray-400">
              <LogOut size={18} />
            </button>
          </div>

          <div className="flex items-center gap-4 md:gap-6 overflow-x-auto hide-scrollbar pb-2 md:pb-0 -mx-4 px-4 md:mx-0 md:px-0 border-t md:border-t-0 border-brand-latte/10 pt-3 md:pt-0">
            <button 
              onClick={() => setActiveTab('products')}
              className={`text-xs uppercase tracking-widest font-bold transition-colors whitespace-nowrap flex-shrink-0 ${activeTab === 'products' ? 'text-brand-flamingo' : 'text-gray-400'}`}
            >
              Products
            </button>
            <button 
              onClick={() => setActiveTab('sales')}
              className={`text-xs uppercase tracking-widest font-bold transition-colors whitespace-nowrap flex-shrink-0 ${activeTab === 'sales' ? 'text-brand-flamingo' : 'text-gray-400'}`}
            >
              Sales & Customers
            </button>
            <button 
              onClick={() => setActiveTab('settings')}
              className={`text-xs uppercase tracking-widest font-bold transition-colors whitespace-nowrap flex-shrink-0 ${activeTab === 'settings' ? 'text-brand-flamingo' : 'text-gray-400'}`}
            >
              Settings
            </button>
            <button onClick={onLogout} className="hidden md:block text-gray-400 hover:text-gray-900 ml-4 border-l border-brand-latte/20 pl-6">
              <LogOut size={18} />
            </button>
          </div>
        </div>
      </nav>

      <div className="container mx-auto px-4 md:px-6 py-8 md:py-12 max-w-6xl">

        {/* PRODUCTS TAB */}
        {activeTab === 'products' && (
          <>
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
              <h2 className="font-serif text-2xl md:text-3xl text-gray-900">Product Management</h2>
              <button 
                onClick={handleCreate}
                className="w-full md:w-auto flex items-center justify-center gap-2 bg-gray-900 text-white px-6 py-3 text-[10px] font-bold uppercase tracking-widest hover:bg-brand-flamingo transition-colors rounded-[2px]"
              >
                <Plus size={14} /> Add Product
              </button>
            </div>

            {isEditing ? (
              <div className="bg-white p-6 md:p-8 border border-brand-latte/20 shadow-sm animate-fade-in max-w-2xl mx-auto rounded-[2px]">
                 <h3 className="font-serif text-xl md:text-2xl mb-6">{editingProduct ? 'Edit Product' : 'New Product'}</h3>
                 <form onSubmit={handleSubmit} className="flex flex-col gap-5 md:gap-6">
                    <div>
                      <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Product Name</label>
                      <input required className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none bg-brand-grey/5" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Price (RM)</label>
                        <input required type="number" className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none bg-brand-grey/5" value={formData.price} onChange={e => setFormData({...formData, price: Number(e.target.value)})} />
                      </div>
                      <div>
                        <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Badge (Optional)</label>
                        <input className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none bg-brand-grey/5" placeholder="e.g. New" value={formData.badge} onChange={e => setFormData({...formData, badge: e.target.value})} />
                      </div>
                    </div>
                    <div>
                      <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Description</label>
                      <textarea required rows={3} className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none bg-brand-grey/5" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
                    </div>
                    <div>
                       <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Material</label>
                       <input className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none bg-brand-grey/5" value={formData.material || ''} onChange={e => setFormData({...formData, material: e.target.value})} />
                    </div>
                    <div>
                       <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Care Instructions</label>
                       <textarea rows={2} className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none bg-brand-grey/5" value={formData.care || ''} onChange={e => setFormData({...formData, care: e.target.value})} />
                    </div>

                    {/* Image Upload Section */}
                    <div>
                      <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Product Image</label>

                      <div className="flex flex-col gap-4">
                        <div className="flex gap-2">
                           <input 
                             className="flex-1 border p-3 text-sm focus:border-brand-flamingo outline-none bg-brand-grey/5" 
                             placeholder="Enter image URL..."
                             value={formData.image} 
                             onChange={e => setFormData({...formData, image: e.target.value})} 
                           />
                           <input 
                             type="file" 
                             accept="image/*" 
                             ref={productFileInputRef}
                             className="hidden"
                             onChange={(e) => handleFileUpload(e, 'product')}
                           />
                           <button 
                              type="button"
                              onClick={() => productFileInputRef.current?.click()}
                              className="bg-brand-latte/20 text-brand-latte hover:bg-brand-latte hover:text-white px-4 py-2 transition-colors flex items-center gap-2"
                              title="Upload Photo"
                           >
                             <Upload size={18} />
                           </button>
                        </div>

                        <div className="flex items-start gap-4 p-4 border border-dashed border-brand-latte/30 bg-brand-grey/5 rounded-[2px]">
                           {formData.image ? (
                             <img src={formData.image} alt="Preview" className="w-20 h-28 object-cover border border-brand-latte/30 bg-white" />
                           ) : (
                             <div className="w-20 h-28 bg-brand-latte/10 flex items-center justify-center text-gray-400 text-xs text-center border border-brand-latte/20">No Image</div>
                           )}
                           <div>
                             <p className="text-xs text-gray-500 font-bold uppercase tracking-wider mb-1">Preview & Tips</p>
                             <p className="text-[10px] text-gray-400 leading-relaxed max-w-xs">
                               Recommended Size: <strong className="text-gray-600">600x800 px</strong> (Portrait 3:4 Aspect Ratio).
                               <br/>
                               Use a transparent or consistent background color for best results.
                             </p>
                           </div>
                        </div>
                      </div>
                    </div>

                    <div className="flex flex-col-reverse md:flex-row justify-end gap-3 mt-4">
                      <button 
                        type="button" 
                        onClick={() => setIsEditing(false)} 
                        className="px-6 py-3 text-[10px] font-bold uppercase tracking-widest text-gray-500 hover:text-gray-900 border border-transparent hover:border-gray-200"
                        disabled={saveStatus !== 'idle'}
                      >
                        Cancel
                      </button>
                      <button 
                        type="submit" 
                        disabled={saveStatus !== 'idle'}
                        className={`text-white px-8 py-3 text-[10px] font-bold uppercase tracking-widest rounded-[2px] flex items-center gap-2 transition-all ${
                          saveStatus === 'saved' ? 'bg-green-600' : 'bg-brand-flamingo hover:bg-brand-flamingo/80'
                        }`}
                      >
                        {saveStatus === 'saving' ? (
                          <><Loader2 size={14} className="animate-spin" /> Saving...</>
                        ) : saveStatus === 'saved' ? (
                          <><Check size={14} /> Saved!</>
                        ) : (
                          'Save Product'
                        )}
                      </button>
                    </div>
                 </form>
              </div>
            ) : (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
                {products.map(product => (
                  <div key={product.id} className="bg-white border border-brand-latte/20 p-4 flex gap-4 items-center group rounded-[2px] shadow-sm">
                    <img src={product.image} alt={product.name} className="w-16 h-16 md:w-20 md:h-20 object-cover bg-gray-100 rounded-[2px]" />
                    <div className="flex-1 min-w-0">
                      <h4 className="font-serif text-base md:text-lg text-gray-900 leading-tight mb-1 truncate">{product.name}</h4>
                      <p className="text-brand-gold font-script text-base md:text-lg">RM {product.price}</p>
                    </div>
                    <div className="flex flex-col gap-2">
                      <button onClick={() => handleEdit(product)} className="text-gray-400 hover:text-brand-flamingo p-1"><Edit2 size={16} /></button>
                      <button onClick={() => handleDelete(product.id)} className="text-gray-400 hover:text-red-400 p-1"><Trash2 size={16} /></button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </>
        )}

        {/* SALES TAB */}
        {activeTab === 'sales' && (
           <div className="animate-fade-in">
             <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
               <div>
                 <h2 className="font-serif text-2xl md:text-3xl text-gray-900">Sales & Customers</h2>
                 <p className="text-xs text-gray-400 mt-1 uppercase tracking-widest">Find customer info and manage orders</p>
               </div>

               <div className="relative w-full md:w-64">
                 <input 
                   type="text" 
                   placeholder="Search orders..."
                   value={searchQuery}
                   onChange={(e) => setSearchQuery(e.target.value)}
                   className="w-full pl-10 pr-4 py-3 bg-white border border-brand-latte/30 focus:border-brand-flamingo outline-none text-sm rounded-full shadow-sm"
                 />
                 <Search size={14} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" />
               </div>
             </div>

             {filteredOrders.length === 0 ? (
               <div className="text-center py-24 bg-white border border-dashed border-brand-latte/30 rounded-[2px]">
                 <Package size={32} className="mx-auto text-brand-latte mb-3 opacity-50" />
                 <p className="text-gray-400 text-sm">No orders found.</p>
               </div>
             ) : (
               <div className="bg-white border border-brand-latte/20 rounded-[2px] shadow-sm overflow-hidden">
                 <div className="overflow-x-auto">
                   <table className="w-full text-left border-collapse min-w-[800px]">
                     <thead>
                       <tr className="bg-brand-grey/10 border-b border-brand-latte/20">
                         <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Order ID / Date</th>
                         <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Customer</th>
                         <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Items</th>
                         <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Total</th>
                         <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Status</th>
                       </tr>
                     </thead>
                     <tbody>
                       {filteredOrders.map(order => (
                         <tr key={order.id} className="border-b border-brand-latte/10 hover:bg-brand-grey/5 transition-colors">
                           <td className="p-4">
                             <div className="font-mono text-xs text-gray-400">#{order.id.slice(-6)}</div>
                             <div className="flex items-center gap-1 text-xs text-gray-500 mt-1">
                               <Calendar size={10} /> {new Date(order.date).toLocaleDateString()}
                             </div>
                           </td>
                           <td className="p-4">
                             <div className="flex items-start gap-2">
                               <div className="bg-brand-latte/20 p-1.5 rounded-full mt-0.5">
                                 <User size={12} className="text-brand-latte" />
                               </div>
                               <div>
                                 <div className="font-serif text-gray-900">{order.customerName}</div>
                                 <div className="text-xs text-gray-400">{order.customerEmail}</div>
                                 <div className="text-[10px] text-gray-400 mt-1 max-w-[150px] leading-tight text-gray-500">{order.shippingAddress}</div>
                               </div>
                             </div>
                           </td>
                           <td className="p-4">
                             <div className="text-xs text-gray-600">
                               {order.items.map(i => (
                                 <div key={i.id} className="mb-1">
                                   {i.quantity}x {i.name}
                                 </div>
                               ))}
                             </div>
                           </td>
                           <td className="p-4 font-bold text-sm text-gray-900">
                             RM {order.total}
                           </td>
                           <td className="p-4">
                             <button 
                               onClick={() => handleStatusToggle(order.id)}
                               className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest border transition-colors ${
                                 order.status === 'delivered' ? 'bg-green-50 border-green-200 text-green-700' :
                                 order.status === 'shipped' ? 'bg-blue-50 border-blue-200 text-blue-700' :
                                 'bg-yellow-50 border-yellow-200 text-yellow-700'
                               }`}
                             >
                               {order.status}
                             </button>
                           </td>
                         </tr>
                       ))}
                     </tbody>
                   </table>
                 </div>
               </div>
             )}
           </div>
        )}

        {/* SETTINGS TAB */}
        {activeTab === 'settings' && (
          <div className="max-w-xl mx-auto animate-fade-in">
            <h2 className="font-serif text-2xl md:text-3xl text-gray-900 mb-6 md:mb-8">Site Settings</h2>

            <div className="bg-white p-6 md:p-8 border border-brand-latte/20 rounded-[2px] shadow-sm">
              <h3 className="font-bold text-xs uppercase tracking-widest text-gray-500 mb-6 flex items-center gap-2">
                <ImageIcon size={16} /> Hero Section Background
              </h3>

              <div className="mb-6">
                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Background Image</label>

                <div className="flex flex-col gap-4">
                  <div className="flex gap-2">
                    <input 
                      className="flex-1 border p-3 text-sm focus:border-brand-flamingo outline-none font-sans bg-brand-grey/5" 
                      placeholder="https://..."
                      value={siteConfig.heroImage} 
                      onChange={(e) => onUpdateSiteConfig({...siteConfig, heroImage: e.target.value})} 
                    />
                     <input 
                       type="file" 
                       accept="image/*" 
                       ref={heroFileInputRef}
                       className="hidden"
                       onChange={(e) => handleFileUpload(e, 'hero')}
                     />
                     <button 
                        type="button"
                        onClick={() => heroFileInputRef.current?.click()}
                        className="bg-brand-latte/20 text-brand-latte hover:bg-brand-latte hover:text-white px-4 py-2 transition-colors flex items-center gap-2"
                        title="Upload Photo"
                     >
                       <Upload size={18} />
                     </button>
                  </div>
                  <p className="text-[10px] text-gray-400">Paste a URL or upload a file. Leave empty to use the default luxury nursery look.</p>
                </div>
              </div>

              {siteConfig.heroImage ? (
                <div className="relative h-48 w-full overflow-hidden mb-6 border border-brand-latte/20 rounded-[2px] group">
                  <img src={siteConfig.heroImage} className="w-full h-full object-cover opacity-80" />
                  <div className="absolute inset-0 flex items-center justify-center bg-black/20 text-white font-bold text-xs uppercase tracking-widest">Preview</div>

                  {/* Remove Button */}
                  <button 
                    onClick={() => onUpdateSiteConfig({...siteConfig, heroImage: ''})}
                    className="absolute top-2 right-2 bg-white/90 text-red-400 p-2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                    title="Remove Image"
                  >
                    <X size={14} />
                  </button>
                </div>
              ) : (
                <div className="p-4 bg-brand-grey/10 text-center text-xs text-gray-400 italic rounded-[2px] mb-6">
                  Using default site theme
                </div>
              )}

              <div className="bg-brand-latte/5 border border-brand-latte/10 p-4 rounded-[2px]">
                 <p className="text-xs text-gray-500 font-bold uppercase tracking-wider mb-2">Recommended Size</p>
                 <p className="text-[10px] text-gray-400 leading-relaxed">
                   Width: <strong>1920px</strong> or higher (Landscape)<br/>
                   Height: <strong>1080px</strong> or higher<br/>
                   Aspect Ratio: <strong>16:9</strong>
                 </p>
              </div>

            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Product, SiteConfig, Order } from '../types';
import { Trash2, Edit2, Plus, Image as ImageIcon, LogOut, Save, Search, User, Package, Calendar, Menu, Upload, X, Loader2, Check, Link } from 'lucide-react';

interface AdminDashboardProps {
  products: Product[];
  orders: Order[];
  siteConfig: SiteConfig;
  onUpdateProducts: (products: Product[]) => void;
  onUpdateSiteConfig: (config: SiteConfig) => void;
  onUpdateOrders: (orders: Order[]) => void;
  onLogout: () => void;
}

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, 
  orders,
  siteConfig, 
  onUpdateProducts, 
  onUpdateSiteConfig,
  onUpdateOrders,
  onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'sales' | 'settings'>('products');
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');

  // Refs for file inputs
  const productFileInputRef = useRef<HTMLInputElement>(null);
  const heroFileInputRef = useRef<HTMLInputElement>(null);

  // Form State
  const [formData, setFormData] = useState<Product>({
    id: '',
    name: '',
    price: 0,
    description: '',
    image: '',
    badge: '',
    material: '',
    care: ''
  });

  const handleEdit = (product: Product) => {
    setFormData(product);
    setEditingProduct(product);
    setIsEditing(true);
    setSaveStatus('idle');
  };

  const handleCreate = () => {
    setFormData({
      id: Date.now().toString(),
      name: '',
      price: 0,
      description: '',
      image: 'https://images.unsplash.com/photo-1513159446162-54eb8bdaa79b?auto=format&fit=crop&q=80',
      badge: '',
      material: '',
      care: ''
    });
    setEditingProduct(null);
    setIsEditing(true);
    setSaveStatus('idle');
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Are you sure you want to remove this product?')) {
      onUpdateProducts(products.filter(p => p.id !== id));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSaveStatus('saving');

    // Simulate a brief delay for better UX
    setTimeout(() => {
      if (editingProduct) {
        onUpdateProducts(products.map(p => p.id === editingProduct.id ? formData : p));
      } else {
        onUpdateProducts([...products, formData]);
      }
      setSaveStatus('saved');

      // Close form after success
      setTimeout(() => {
        setIsEditing(false);
        setSaveStatus('idle');
      }, 500);
    }, 600);
  };

  const handleStatusToggle = (orderId: string) => {
    onUpdateOrders(orders.map(o => {
      if (o.id === orderId) {
        return { 
          ...o, 
          status: o.status === 'pending' ? 'shipped' : o.status === 'shipped' ? 'delivered' : 'pending' 
        };
      }
      return o;
    }));
  };

  // Image Upload Handler
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'product' | 'hero') => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        alert("Warning: Large images may slow down the site. We recommend images under 2MB.");
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        if (type === 'product') {
          setFormData(prev => ({ ...prev, image: result }));
        } else {
          onUpdateSiteConfig({ ...siteConfig, heroImage: result });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  // Filter Orders
  const filteredOrders = orders.filter(order => 
    order.customerName.toLowerCase().includes(searchQuery.toLowerCase()) || 
    order.customerEmail.toLowerCase().includes(searchQuery.toLowerCase()) ||
    order.id.includes(searchQuery)
  );

  return (
    <div className="min-h-screen bg-brand-grey/10 font-sans pb-20">
      {/* Admin Nav - Scrollable on mobile */}
      <nav className="bg-white border-b border-brand-latte/20 sticky top-0 z-40">
        <div className="px-4 md:px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <span className="font-serif text-lg md:text-xl font-bold tracking-wider">ONCE UPON</span>
              <span className="bg-brand-grey px-2 py-0.5 text-[10px] uppercase tracking-wider font-bold text-gray-500 rounded">Admin</span>
            </div>
            <button onClick={onLogout} className="md:hidden text-gray-400">
              <LogOut size={18} />
            </button>
          </div>

          <div className="flex items-center gap-4 md:gap-6 overflow-x-auto hide-scrollbar pb-2 md:pb-0 -mx-4 px-4 md:mx-0 md:px-0 border-t md:border-t-0 border-brand-latte/10 pt-3 md:pt-0">
            <button 
              onClick={() => setActiveTab('products')}
              className={`text-xs uppercase tracking-widest font-bold transition-colors whitespace-nowrap flex-shrink-0 ${activeTab === 'products' ? 'text-brand-flamingo' : 'text-gray-400'}`}
            >
              Products
            </button>
            <button 
              onClick={() => setActiveTab('sales')}
              className={`text-xs uppercase tracking-widest font-bold transition-colors whitespace-nowrap flex-shrink-0 ${activeTab === 'sales' ? 'text-brand-flamingo' : 'text-gray-400'}`}
            >
              Sales & Customers
            </button>
            <button 
              onClick={() => setActiveTab('settings')}
              className={`text-xs uppercase tracking-widest font-bold transition-colors whitespace-nowrap flex-shrink-0 ${activeTab === 'settings' ? 'text-brand-flamingo' : 'text-gray-400'}`}
            >
              Settings
            </button>
            <button onClick={onLogout} className="hidden md:block text-gray-400 hover:text-gray-900 ml-4 border-l border-brand-latte/20 pl-6">
              <LogOut size={18} />
            </button>
          </div>
        </div>
      </nav>

      <div className="container mx-auto px-4 md:px-6 py-8 md:py-12 max-w-6xl">

        {/* PRODUCTS TAB */}
        {activeTab === 'products' && (
          <>
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
              <h2 className="font-serif text-2xl md:text-3xl text-gray-900">Product Management</h2>
              <button 
                onClick={handleCreate}
                className="w-full md:w-auto flex items-center justify-center gap-2 bg-gray-900 text-white px-6 py-3 text-[10px] font-bold uppercase tracking-widest hover:bg-brand-flamingo transition-colors rounded-[2px]"
              >
                <Plus size={14} /> Add Product
              </button>
            </div>

            {isEditing ? (
              <div className="bg-white p-6 md:p-8 border border-brand-latte/20 shadow-sm animate-fade-in max-w-2xl mx-auto rounded-[2px]">
                 <h3 className="font-serif text-xl md:text-2xl mb-6">{editingProduct ? 'Edit Product' : 'New Product'}</h3>
                 <form onSubmit={handleSubmit} className="flex flex-col gap-5 md:gap-6">
                    <div>
                      <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Product Name</label>
                      <input required className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none bg-brand-grey/5" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Price (RM)</label>
                        <input required type="number" className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none bg-brand-grey/5" value={formData.price} onChange={e => setFormData({...formData, price: Number(e.target.value)})} />
                      </div>
                      <div>
                        <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Badge (Optional)</label>
                        <input className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none bg-brand-grey/5" placeholder="e.g. New" value={formData.badge} onChange={e => setFormData({...formData, badge: e.target.value})} />
                      </div>
                    </div>
                    <div>
                      <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Description</label>
                      <textarea required rows={3} className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none bg-brand-grey/5" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
                    </div>
                    <div>
                       <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Material</label>
                       <input className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none bg-brand-grey/5" value={formData.material || ''} onChange={e => setFormData({...formData, material: e.target.value})} />
                    </div>
                    <div>
                       <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Care Instructions</label>
                       <textarea rows={2} className="w-full border p-3 text-sm focus:border-brand-flamingo outline-none bg-brand-grey/5" value={formData.care || ''} onChange={e => setFormData({...formData, care: e.target.value})} />
                    </div>

                    {/* Image Upload/URL Section */}
                    <div>
                      <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Product Image</label>

                      <div className="flex flex-col gap-4">
                        <div className="flex gap-2 items-center">
                           <div className="relative flex-1">
                             <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                               <Link size={14} />
                             </div>
                             <input 
                               className="w-full border p-3 pl-9 pr-8 text-sm focus:border-brand-flamingo outline-none bg-brand-grey/5 font-mono text-xs" 
                               placeholder="Paste Image URL here..."
                               value={formData.image} 
                               onChange={e => setFormData({...formData, image: e.target.value})} 
                             />
                             {formData.image && (
                               <button 
                                 type="button"
                                 onClick={() => setFormData({...formData, image: ''})}
                                 className="absolute right-2 top-1/2 -translate-y-1/2 text-gray-400 hover:text-red-400"
                               >
                                 <X size={14} />
                               </button>
                             )}
                           </div>

                           <span className="text-[10px] text-gray-400 font-bold uppercase mx-1">OR</span>

                           <button 
                              type="button"
                              onClick={() => productFileInputRef.current?.click()}
                              className="bg-white border border-brand-latte/30 text-gray-600 hover:text-brand-flamingo hover:border-brand-flamingo px-4 py-3 transition-colors flex items-center gap-2 text-xs font-bold uppercase tracking-wider min-w-[100px] justify-center"
                              title="Upload Photo"
                           >
                             <Upload size={14} /> Upload
                           </button>
                           <input 
                             type="file" 
                             accept="image/*" 
                             ref={productFileInputRef}
                             className="hidden"
                             onChange={(e) => handleFileUpload(e, 'product')}
                           />
                        </div>

                        <div className="flex items-start gap-4 p-4 border border-dashed border-brand-latte/30 bg-brand-grey/5 rounded-[2px]">
                           {formData.image ? (
                             <img src={formData.image} alt="Preview" className="w-20 h-28 object-cover border border-brand-latte/30 bg-white" />
                           ) : (
                             <div className="w-20 h-28 bg-brand-latte/10 flex items-center justify-center text-gray-400 text-xs text-center border border-brand-latte/20">No Image</div>
                           )}
                           <div>
                             <p className="text-xs text-gray-500 font-bold uppercase tracking-wider mb-1">Preview & Tips</p>
                             <p className="text-[10px] text-gray-400 leading-relaxed max-w-xs">
                               Recommended Size: <strong className="text-gray-600">600x800 px</strong> (Portrait 3:4 Aspect Ratio).
                               <br/>
                               Supported: JPG, PNG, WebP (via URL or Upload).
                             </p>
                           </div>
                        </div>
                      </div>
                    </div>

                    <div className="flex flex-col-reverse md:flex-row justify-end gap-3 mt-4">
                      <button 
                        type="button" 
                        onClick={() => setIsEditing(false)} 
                        className="px-6 py-3 text-[10px] font-bold uppercase tracking-widest text-gray-500 hover:text-gray-900 border border-transparent hover:border-gray-200"
                        disabled={saveStatus !== 'idle'}
                      >
                        Cancel
                      </button>
                      <button 
                        type="submit" 
                        disabled={saveStatus !== 'idle'}
                        className={`text-white px-8 py-3 text-[10px] font-bold uppercase tracking-widest rounded-[2px] flex items-center gap-2 transition-all ${
                          saveStatus === 'saved' ? 'bg-green-600' : 'bg-brand-flamingo hover:bg-brand-flamingo/80'
                        }`}
                      >
                        {saveStatus === 'saving' ? (
                          <><Loader2 size={14} className="animate-spin" /> Saving...</>
                        ) : saveStatus === 'saved' ? (
                          <><Check size={14} /> Saved!</>
                        ) : (
                          'Save Product'
                        )}
                      </button>
                    </div>
                 </form>
              </div>
            ) : (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
                {products.map(product => (
                  <div key={product.id} className="bg-white border border-brand-latte/20 p-4 flex gap-4 items-center group rounded-[2px] shadow-sm">
                    <img src={product.image} alt={product.name} className="w-16 h-16 md:w-20 md:h-20 object-cover bg-gray-100 rounded-[2px]" />
                    <div className="flex-1 min-w-0">
                      <h4 className="font-serif text-base md:text-lg text-gray-900 leading-tight mb-1 truncate">{product.name}</h4>
                      <p className="text-brand-gold font-script text-base md:text-lg">RM {product.price}</p>
                    </div>
                    <div className="flex flex-col gap-2">
                      <button onClick={() => handleEdit(product)} className="text-gray-400 hover:text-brand-flamingo p-1"><Edit2 size={16} /></button>
                      <button onClick={() => handleDelete(product.id)} className="text-gray-400 hover:text-red-400 p-1"><Trash2 size={16} /></button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </>
        )}

        {/* SALES TAB */}
        {activeTab === 'sales' && (
           <div className="animate-fade-in">
             <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
               <div>
                 <h2 className="font-serif text-2xl md:text-3xl text-gray-900">Sales & Customers</h2>
                 <p className="text-xs text-gray-400 mt-1 uppercase tracking-widest">Find customer info and manage orders</p>
               </div>

               <div className="relative w-full md:w-64">
                 <input 
                   type="text" 
                   placeholder="Search orders..."
                   value={searchQuery}
                   onChange={(e) => setSearchQuery(e.target.value)}
                   className="w-full pl-10 pr-4 py-3 bg-white border border-brand-latte/30 focus:border-brand-flamingo outline-none text-sm rounded-full shadow-sm"
                 />
                 <Search size={14} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" />
               </div>
             </div>

             {filteredOrders.length === 0 ? (
               <div className="text-center py-24 bg-white border border-dashed border-brand-latte/30 rounded-[2px]">
                 <Package size={32} className="mx-auto text-brand-latte mb-3 opacity-50" />
                 <p className="text-gray-400 text-sm">No orders found.</p>
               </div>
             ) : (
               <div className="bg-white border border-brand-latte/20 rounded-[2px] shadow-sm overflow-hidden">
                 <div className="overflow-x-auto">
                   <table className="w-full text-left border-collapse min-w-[800px]">
                     <thead>
                       <tr className="bg-brand-grey/10 border-b border-brand-latte/20">
                         <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Order ID / Date</th>
                         <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Customer</th>
                         <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Items</th>
                         <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Total</th>
                         <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Status</th>
                       </tr>
                     </thead>
                     <tbody>
                       {filteredOrders.map(order => (
                         <tr key={order.id} className="border-b border-brand-latte/10 hover:bg-brand-grey/5 transition-colors">
                           <td className="p-4">
                             <div className="font-mono text-xs text-gray-400">#{order.id.slice(-6)}</div>
                             <div className="flex items-center gap-1 text-xs text-gray-500 mt-1">
                               <Calendar size={10} /> {new Date(order.date).toLocaleDateString()}
                             </div>
                           </td>
                           <td className="p-4">
                             <div className="flex items-start gap-2">
                               <div className="bg-brand-latte/20 p-1.5 rounded-full mt-0.5">
                                 <User size={12} className="text-brand-latte" />
                               </div>
                               <div>
                                 <div className="font-serif text-gray-900">{order.customerName}</div>
                                 <div className="text-xs text-gray-400">{order.customerEmail}</div>
                                 <div className="text-[10px] text-gray-400 mt-1 max-w-[150px] leading-tight text-gray-500">{order.shippingAddress}</div>
                               </div>
                             </div>
                           </td>
                           <td className="p-4">
                             <div className="text-xs text-gray-600">
                               {order.items.map(i => (
                                 <div key={i.id} className="mb-1">
                                   {i.quantity}x {i.name}
                                 </div>
                               ))}
                             </div>
                           </td>
                           <td className="p-4 font-bold text-sm text-gray-900">
                             RM {order.total}
                           </td>
                           <td className="p-4">
                             <button 
                               onClick={() => handleStatusToggle(order.id)}
                               className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest border transition-colors ${
                                 order.status === 'delivered' ? 'bg-green-50 border-green-200 text-green-700' :
                                 order.status === 'shipped' ? 'bg-blue-50 border-blue-200 text-blue-700' :
                                 'bg-yellow-50 border-yellow-200 text-yellow-700'
                               }`}
                             >
                               {order.status}
                             </button>
                           </td>
                         </tr>
                       ))}
                     </tbody>
                   </table>
                 </div>
               </div>
             )}
           </div>
        )}

        {/* SETTINGS TAB */}
        {activeTab === 'settings' && (
          <div className="max-w-xl mx-auto animate-fade-in">
            <h2 className="font-serif text-2xl md:text-3xl text-gray-900 mb-6 md:mb-8">Site Settings</h2>

            <div className="bg-white p-6 md:p-8 border border-brand-latte/20 rounded-[2px] shadow-sm">
              <h3 className="font-bold text-xs uppercase tracking-widest text-gray-500 mb-6 flex items-center gap-2">
                <ImageIcon size={16} /> Hero Section Background
              </h3>

              <div className="mb-6">
                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-2">Background Image</label>

                <div className="flex flex-col gap-4">
                  <div className="flex gap-2 items-center">
                    <div className="relative flex-1">
                       <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                         <Link size={14} />
                       </div>
                       <input 
                        className="w-full border p-3 pl-9 pr-8 text-sm focus:border-brand-flamingo outline-none font-mono bg-brand-grey/5 text-xs" 
                        placeholder="Paste Image URL here..."
                        value={siteConfig.heroImage} 
                        onChange={(e) => onUpdateSiteConfig({...siteConfig, heroImage: e.target.value})} 
                      />
                      {siteConfig.heroImage && (
                        <button 
                          type="button"
                          onClick={() => onUpdateSiteConfig({...siteConfig, heroImage: ''})}
                          className="absolute right-2 top-1/2 -translate-y-1/2 text-gray-400 hover:text-red-400"
                        >
                          <X size={14} />
                        </button>
                      )}
                    </div>

                     <span className="text-[10px] text-gray-400 font-bold uppercase mx-1">OR</span>

                     <button 
                        type="button"
                        onClick={() => heroFileInputRef.current?.click()}
                        className="bg-white border border-brand-latte/30 text-gray-600 hover:text-brand-flamingo hover:border-brand-flamingo px-4 py-3 transition-colors flex items-center gap-2 text-xs font-bold uppercase tracking-wider min-w-[100px] justify-center"
                        title="Upload Photo"
                     >
                       <Upload size={14} /> Upload
                     </button>
                     <input 
                       type="file" 
                       accept="image/*" 
                       ref={heroFileInputRef}
                       className="hidden"
                       onChange={(e) => handleFileUpload(e, 'hero')}
                     />
                  </div>
                  <p className="text-[10px] text-gray-400">Paste a URL or upload a file. Leave empty to use the default luxury nursery look.</p>
                </div>
              </div>

              {siteConfig.heroImage ? (
                <div className="relative h-48 w-full overflow-hidden mb-6 border border-brand-latte/20 rounded-[2px] group">
                  <img src={siteConfig.heroImage} className="w-full h-full object-cover opacity-80" />
                  <div className="absolute inset-0 flex items-center justify-center bg-black/20 text-white font-bold text-xs uppercase tracking-widest">Preview</div>

                  {/* Remove Button */}
                  <button 
                    onClick={() => onUpdateSiteConfig({...siteConfig, heroImage: ''})}
                    className="absolute top-2 right-2 bg-white/90 text-red-400 p-2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                    title="Remove Image"
                  >
                    <X size={14} />
                  </button>
                </div>
              ) : (
                <div className="p-4 bg-brand-grey/10 text-center text-xs text-gray-400 italic rounded-[2px] mb-6">
                  Using default site theme
                </div>
              )}

              <div className="bg-brand-latte/5 border border-brand-latte/10 p-4 rounded-[2px]">
                 <p className="text-xs text-gray-500 font-bold uppercase tracking-wider mb-2">Recommended Size</p>
                 <p className="text-[10px] text-gray-400 leading-relaxed">
                   Width: <strong>1920px</strong> or higher (Landscape)<br/>
                   Height: <strong>1080px</strong> or higher<br/>
                   Aspect Ratio: <strong>16:9</strong>
                 </p>
              </div>

            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import { Product } from './types';

export const PRODUCTS: Product[] = [
  {
    id: '1',
