                   value={searchQuery}
                   onChange={(e) => setSearchQuery(e.target.value)}
                   className="w-full pl-10 pr-4 py-3 bg-white border border-brand-latte/30 focus:border-brand-flamingo outline-none text-sm rounded-full shadow-sm"
                 />
                 <Search size={14} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" />
               </div>
             </div>

             {filteredOrders.length === 0 ? (
               <div className="text-center py-24 bg-white border border-dashed border-brand-latte/30 rounded-[2px]">
                 <Package size={32} className="mx-auto text-brand-latte mb-3 opacity-50" />
                 <p className="text-gray-400 text-sm">No orders found.</p>
               </div>
             ) : (
               <div className="bg-white border border-brand-latte/20 rounded-[2px] shadow-sm overflow-hidden">
                 <div className="overflow-x-auto">
                   <table className="w-full text-left border-collapse min-w-[800px]">
                     <thead>
                       <tr className="bg-brand-grey/10 border-b border-brand-latte/20">
                         <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Order ID / Date</th>
                         <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Customer</th>
                         <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Items</th>
                         <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Total</th>
                         <th className="p-4 text-[10px] font-bold uppercase tracking-widest text-gray-500">Status</th>
                       </tr>
                     </thead>
                     <tbody>
                       {filteredOrders.map(order => (
                         <tr key={order.id} className="border-b border-brand-latte/10 hover:bg-brand-grey/5 transition-colors">
                           <td className="p-4">
                             <div className="font-mono text-xs text-gray-400">#{order.id.slice(-6)}</div>
                             <div className="flex items-center gap-1 text-xs text-gray-500 mt-1">
                               <Calendar size={10} /> {new Date(order.date).toLocaleDateString()}
                             </div>
                           </td>
                           <td className="p-4">
                             <div className="flex items-start gap-2">
                               <div className="bg-brand-latte/20 p-1.5 rounded-full mt-0.5">
                                 <User size={12} className="text-brand-latte" />
                               </div>
                               <div>
                                 <div className="font-serif text-gray-900">{order.customerName}</div>
                                 <div className="text-xs text-gray-400">{order.customerEmail}</div>
                                 <div className="text-[10px] text-gray-400 mt-1 max-w-[150px] leading-tight text-gray-500">{order.shippingAddress}</div>
                               </div>
                             </div>
                           </td>
                           <td className="p-4">
                             <div className="text-xs text-gray-600">
                               {order.items.map(i => (
                                 <div key={i.id} className="mb-1">
                                   {i.quantity}x {i.name}
                                 </div>
                               ))}
                             </div>
                           </td>
                           <td className="p-4 font-bold text-sm text-gray-900">
                             RM {order.total}
                           </td>
                           <td className="p-4">
                             <button 
                               onClick={() => handleStatusToggle(order.id, order.status)}
                               className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest border transition-colors ${
                                 order.status === 'delivered' ? 'bg-green-50 border-green-200 text-green-700' :
                                 order.status === 'shipped' ? 'bg-blue-50 border-blue-200 text-blue-700' :
                                 'bg-yellow-50 border-yellow-200 text-yellow-700'
                               }`}
                             >
                               {order.status}
                             </button>
                           </td>
                         </tr>
                       ))}
                     </tbody>
                   </table>
                 </div>
               </div>
             )}
           </div>
        )}

        {/* SETTINGS TAB - Simplified for now */}
        {activeTab === 'settings' && (
          <div className="max-w-xl mx-auto animate-fade-in text-center p-12">
             <p className="text-gray-400">Site Settings configuration via Firebase is currently read-only in this demo version.</p>
          </div>
        )}
      </div>
    </div>
  );
};

import { initializeApp } from 'firebase/app';
import { getFirestore, collection, addDoc, updateDoc, deleteDoc, doc, onSnapshot, query, orderBy } from 'firebase/firestore';
import { getStorage, ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import { Product, Order, SiteConfig } from './types';

// ------------------------------------------------------------------
// INSTRUCTIONS:
// 1. Go to Firebase Console -> Project Settings
// 2. Scroll down to "Your apps"
// 3. Copy the values from the SDK setup and paste them below
// ------------------------------------------------------------------
const firebaseConfig = {
  apiKey: "PASTE_YOUR_API_KEY_HERE",
  authDomain: "PASTE_YOUR_AUTH_DOMAIN_HERE",
  projectId: "PASTE_YOUR_PROJECT_ID_HERE",
  storageBucket: "PASTE_YOUR_STORAGE_BUCKET_HERE",
  messagingSenderId: "PASTE_YOUR_SENDER_ID_HERE",
  appId: "PASTE_YOUR_APP_ID_HERE"
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);
export const db = getFirestore(app);
export const storage = getStorage(app);

// --- HELPER FUNCTIONS ---

// Products
export const subscribeToProducts = (callback: (products: Product[]) => void) => {
  const q = query(collection(db, 'products'), orderBy('name'));
  return onSnapshot(q, (snapshot) => {
    const products = snapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data()
    })) as Product[];
    callback(products);
  }, (error) => {
    console.error("Error fetching products:", error);
    // Fallback for demo if Firebase isn't configured yet
    callback([]); 
  });
};

export const addProductToDb = async (product: Omit<Product, 'id'>) => {
  return await addDoc(collection(db, 'products'), product);
};

export const updateProductInDb = async (id: string, updates: Partial<Product>) => {
  const docRef = doc(db, 'products', id);
  await updateDoc(docRef, updates);
};

export const deleteProductFromDb = async (id: string) => {
  await deleteDoc(doc(db, 'products', id));
};

// Orders
export const createOrderInDb = async (order: Omit<Order, 'id'>) => {
  return await addDoc(collection(db, 'orders'), order);
};

export const subscribeToOrders = (callback: (orders: Order[]) => void) => {
  const q = query(collection(db, 'orders'), orderBy('date', 'desc'));
  return onSnapshot(q, (snapshot) => {
    const orders = snapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data()
    })) as Order[];
    callback(orders);
  });
};

export const updateOrderStatusInDb = async (id: string, status: Order['status']) => {
  const docRef = doc(db, 'orders', id);
  await updateDoc(docRef, { status });
};

// Storage
export const uploadImage = async (file: File): Promise<string> => {
  const storageRef = ref(storage, `images/${Date.now()}_${file.name}`);
  const snapshot = await uploadBytes(storageRef, file);
  return await getDownloadURL(snapshot.ref);
};

// Site Config
// (We can use a specific document ID like 'main' in a 'config' collection)
export const updateSiteConfigInDb = async (config: SiteConfig) => {
  // For simplicity in this demo, we'll just log it or you can implement 
  // a 'settings' collection later.
  console.log("Saving config to DB:", config);
};

